import{_ as e,o as t,c as r,ak as n}from"./chunks/framework.DkeEmzcj.js";const h=JSON.parse('{"title":"Backend & API - Punjab Educare","description":"","frontmatter":{"title":"Backend & API - Punjab Educare"},"headers":[],"relativePath":"punjab-educare/api.md","filePath":"punjab-educare/api.md","lastUpdated":1772241126000}'),i={name:"punjab-educare/api.md"};function s(o,a,p,c,d,l){return t(),r("div",null,[...a[0]||(a[0]=[n('<h1 id="backend-api" tabindex="-1">Backend &amp; API <a class="header-anchor" href="#backend-api" aria-label="Permalink to “Backend &amp; API”">​</a></h1><p>Punjab Educare is powered by an <strong>internal</strong> backend API built for the platform’s own applications (Android and desktop tooling).<br> It is not intended for public/third‑party integration, and this documentation intentionally avoids sharing implementation details that could enable external usage.</p><h2 id="what-the-backend-supports" tabindex="-1">What the backend supports <a class="header-anchor" href="#what-the-backend-supports" aria-label="Permalink to “What the backend supports”">​</a></h2><ul><li>Student experiences: practice flow, quiz participation, and progress-related data surfaces.</li><li>Teacher experiences: onboarding/verification gates, classroom workflows, quiz setup, and question submissions.</li><li>Admin operations (internal): content review/moderation, platform management, and operational tooling.</li></ul><h2 id="tech-stack" tabindex="-1">Tech Stack <a class="header-anchor" href="#tech-stack" aria-label="Permalink to “Tech Stack”">​</a></h2><p><strong>API Backend (Laravel + Octane)</strong><br> Laravel provides a maintainable foundation, with Laravel Octane used to support higher-throughput API workloads.</p><p><strong>Database (MariaDB) + Cache (Redis)</strong><br> MariaDB stores core platform data, and Redis is used to reduce latency and improve performance through caching.</p><h2 id="core-capabilities" tabindex="-1">Core Capabilities <a class="header-anchor" href="#core-capabilities" aria-label="Permalink to “Core Capabilities”">​</a></h2><p><strong>Content structure</strong><br> Curriculum-aligned organization across classes, subjects, and topics to support discovery and structured learning flows.</p><p><strong>Question bank + review pipeline</strong><br> Teacher-submitted questions go through a review process by a trusted internal admin team before being published to the main question bank.</p><p><strong>Quizzes &amp; assessment</strong><br> Supports practice attempts and class-based quizzes, including question delivery, attempt submission, and results visibility where appropriate.</p><p><strong>Communication surfaces</strong><br> Supports app-facing updates such as notifications and time-sensitive messages.</p><p><strong>Feedback &amp; support</strong><br> Supports user feedback capture and structured issue handling to keep improving platform quality.</p>',13)])])}const b=e(i,[["render",s]]);export{h as __pageData,b as default};
